 1→import AsyncStorage from '@react-native-async-storage/async-storage';
 2→import { createClient, SupabaseClient } from '@supabase/supabase-js';
 3→import { IS_SUPABASE_CONFIGURED, MOBILE_ENV } from '../config/env';
 4→
 5→const stripTrailingSlashes = (value: string): string => value.replace(/\/+$/, '');
 6→
 7→const createSupabaseClient = (): SupabaseClient => {
 8→  const resolvedSupabaseUrl = stripTrailingSlashes(MOBILE_ENV.SUPABASE_URL);
 9→  const resolvedSupabaseKey = MOBILE_ENV.SUPABASE_ANON_KEY;
10→
11→  return createClient(resolvedSupabaseUrl, resolvedSupabaseKey, {
12→    auth: {
13→      autoRefreshToken: true,
14→      persistSession: true,
15→      detectSessionInUrl: false,
16→      storage: AsyncStorage,
17→    },
18→    realtime: {
19→      params: {
20→        eventsPerSecond: 2,
21→      },
22→    },
23→  });
24→};
25→
26→export const supabase: SupabaseClient | null = IS_SUPABASE_CONFIGURED
27→  ? createSupabaseClient()
28→  : null;
