 21→export function ForgotPasswordScreen({navigation}: Props) {
 22→  const {colors, isDark} = useTheme();
 23→  const [email, setEmail] = useState('');
 24→  const [loading, setLoading] = useState(false);
 25→  const [sent, setSent] = useState(false);
 26→  const [focusedField, setFocusedField] = useState<string | null>(null);
 27→
 28→  const onSubmit = async () => {
 29→    if (email.trim().length < 5) return;
 30→    try {
 31→      setLoading(true);
 32→      // Use Supabase directly for password reset
 33→      const {createClient} = await import('@supabase/supabase-js');
 34→      const {MOBILE_ENV} = await import('../../config/env');
 35→      if (MOBILE_ENV.SUPABASE_URL && MOBILE_ENV.SUPABASE_ANON_KEY) {
 36→        const supabase = createClient(
 37→          MOBILE_ENV.SUPABASE_URL,
 38→          MOBILE_ENV.SUPABASE_ANON_KEY,
 39→        );
 40→        await supabase.auth.resetPasswordForEmail(email.trim());
 41→      }
 42→      setSent(true);
 43→    } catch {
 44→      Alert.alert('Error', 'Failed to send reset email. Please try again.');
 45→    } finally {
 46→      setLoading(false);
 47→    }
 48→  };
 49→
 50→  const inputStyle = [
 51→    styles.input,
 52→    {
 53→      backgroundColor: isDark ? colors.bgElevated : colors.bgPrimary,
 54→      borderColor:
 55→        focusedField === 'email' ? colors.accentAmber : colors.borderCard,
 56→      color: colors.textPrimary,
 57→    },
 58→  ];
 59→
 60→  return (
 61→    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
 62→      <KeyboardAvoidingView
 63→        style={styles.flex}
